const normalizeVerify = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return String(value);
};

const formEncode = (pairs) => Object.entries(pairs)
    .map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v))
    .join('&');

const tokenUrl = env.get('AI_INSIGHT_TRINO__OIDC_TOKEN_URL') || '';
const clientId = env.get('AI_INSIGHT_TRINO__OIDC_CLIENT_ID') || '';
const clientSecret = env.get('AI_INSIGHT_TRINO__OIDC_CLIENT_SECRET') || '';
const username = env.get('AI_INSIGHT_TRINO__OIDC_USERNAME') || '';
const password = env.get('AI_INSIGHT_TRINO__OIDC_PASSWORD') || '';
const scope = env.get('AI_INSIGHT_TRINO__OIDC_SCOPE') || 'openid';
const oidcVerify = normalizeVerify(env.get('AI_INSIGHT_TRINO__OIDC_VERIFY'), true);

const now = Date.now();
const cacheKey = ['trino-auth', tokenUrl, clientId, username].join('|');
const cacheMap = global.get('aiInsightTrinoTokenCache') || {};
const cached = cacheMap[cacheKey];
if (!msg.trinoForceRefresh && cached && cached.accessToken && Number(cached.expiresAt || 0) > now + 30000) {
    msg.trinoAuth = {
        access_token: cached.accessToken,
        expires_at: cached.expiresAt,
        source: 'cache',
        oidc_verify: oidcVerify,
    };
    return [msg, null, null];
}

if (!tokenUrl || !clientId || !clientSecret || !username || !password) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Trino authentication failed' };
    return [null, msg, null];
}

msg.method = 'POST';
msg.url = tokenUrl;
msg.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
msg.payload = formEncode({
    grant_type: 'password',
    client_id: clientId,
    client_secret: clientSecret,
    username,
    password,
    scope,
});
msg.rejectUnauthorized = oidcVerify !== false;
msg._tokenCacheKey = cacheKey;
msg._oidcVerify = oidcVerify;
return [null, null, msg];

if (Number(msg.statusCode || 0) < 200 || Number(msg.statusCode || 0) >= 300) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Trino authentication failed' };
    return [null, msg];
}

const payload = msg.payload || {};
const accessToken = payload.access_token;
if (!accessToken) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Trino authentication failed' };
    return [null, msg];
}

const expiresIn = Number(payload.expires_in || 300);
const expiresAt = Date.now() + Math.max(expiresIn - 15, 30) * 1000;
const cacheMap = global.get('aiInsightTrinoTokenCache') || {};
if (msg._tokenCacheKey) {
    cacheMap[msg._tokenCacheKey] = { accessToken, expiresAt };
    global.set('aiInsightTrinoTokenCache', cacheMap);
}

msg.trinoAuth = {
    access_token: String(accessToken),
    expires_at: expiresAt,
    source: 'oidc_password_grant',
    oidc_verify: msg._oidcVerify,
};
return [msg, null];

const parseVerifySetting = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return String(value);
};

const quoteIdent = (v) => '"' + String(v).replace(/"/g, '""') + '"';

const req = msg.anomalyRequest || {};
if (!req.start_ts || !req.end_ts) {
    msg.statusCode = 400;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'start_ts and end_ts are required' };
    return [null, msg];
}

