msg.method = 'POST';
msg.url = `${scheme}://${host}:${port}/v1/statement`;
msg.headers = {
    'Authorization': `Bearer ${accessToken}`,
    'X-Trino-User': user,
    'X-Trino-Catalog': catalog,
    'X-Trino-Schema': schema,
    'Content-Type': 'text/plain; charset=utf-8',
};
msg.payload = sql;

if (trinoVerifySetting === false) {
    msg.rejectUnauthorized = false;
} else if (typeof trinoVerifySetting === 'string') {
    msg.rejectUnauthorized = false;
} else {
    msg.rejectUnauthorized = true;
}

msg._trinoMeta = { catalog, schema, table };
msg._trinoRows = [];
msg._trinoColumns = [];
msg._trinoNextHeaders = {
    'Authorization': `Bearer ${accessToken}`,
    'X-Trino-User': user,
