if (status === 401 || status === 403 || status >= 400) {
    msg.statusCode = 502;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = { detail: 'Upstream dependency failure while generating insight' };
    return [null, null, msg];
}

const body = msg.payload || {};
if (Array.isArray(body.columns) && body.columns.length > 0 && (!Array.isArray(msg._trinoColumns) || msg._trinoColumns.length === 0)) {
    msg._trinoColumns = body.columns.map((c) => c.name);
}

const columns = Array.isArray(msg._trinoColumns) ? msg._trinoColumns : [];
const rows = Array.isArray(msg._trinoRows) ? msg._trinoRows : [];
const data = Array.isArray(body.data) ? body.data : [];
for (const row of data) {
    if (!Array.isArray(row)) continue;
    const mapped = {};
    for (let i = 0; i < columns.length; i += 1) {
        mapped[columns[i]] = row[i];
    }
    rows.push(mapped);
}
msg._trinoRows = rows;

if (body.nextUri) {
    msg.method = 'GET';
    msg.url = String(body.nextUri);
    msg.headers = Object.assign({}, msg._trinoNextHeaders || {});
    msg.payload = '';
    return [msg, null, null];
}

msg.trinoRows = rows;
msg.trinoQuery = Object.assign({}, msg._trinoMeta || {}, {
    row_count: rows.length,
});
return [null, msg, null];

const uuidFromMathRandom = () => 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (char) => {
    const rand = Math.random() * 16 | 0;
    const value = char === 'x' ? rand : ((rand & 0x3) | 0x8);
    return value.toString(16);
});
const runtimeCrypto = global.get('crypto');
const makeOutputId = () => (runtimeCrypto && typeof runtimeCrypto.randomUUID === 'function') ? runtimeCrypto.randomUUID() : uuidFromMathRandom();

const toBool = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const toNumber = (value, fallback) => {
    const n = Number(value);
    return Number.isFinite(n) ? n : fallback;
};

const rows = Array.isArray(msg.trinoRows) ? msg.trinoRows : [];
const req = msg.anomalyRequest || {};
const access = msg.accessContext || {};
const includeData = !!req.include_data;
const timezone = req.timezone || 'UTC';
const threshold = toNumber(req.robust_z_threshold, 3.5);

const parseMetric = (row, key) => {
    const value = Number(row[key]);
    return Number.isFinite(value) ? value : null;
};

const normalizeTimestamp = (ts) => {
    if (ts === undefined || ts === null || ts === '') return null;
    const raw = String(ts).trim();
    const normalized = raw.replace(' UTC', 'Z').replace(' ', 'T');
    const d = new Date(normalized);
    if (Number.isNaN(d.getTime())) return raw;
    return d.toISOString().replace('.000Z', '+00:00');
};

const metrics = ['avg_consumption_kw', 'avg_generation_kw', 'estimated_hourly_cost_eur'];
const summarizeMetric = (key) => {
    const values = rows.map((r) => parseMetric(r, key)).filter((v) => v !== null);
    if (values.length === 0) return null;
    const sorted = [...values].sort((a, b) => a - b);
    const sum = values.reduce((a, b) => a + b, 0);
    const mean = sum / values.length;
    const median = sorted[Math.floor(sorted.length / 2)];
    const deviations = values.map((v) => Math.abs(v - median)).sort((a, b) => a - b);
    const mad = deviations[Math.floor(deviations.length / 2)] || 0;
    return {
        metric: key,
        count: values.length,
        min: Number(sorted[0].toFixed(4)),
        max: Number(sorted[sorted.length - 1].toFixed(4)),
        mean: Number(mean.toFixed(4)),
        median: Number(median.toFixed(4)),
        median_raw: median,
        mad: Number(mad.toFixed(4)),
        mad_raw: mad,
    };
};

const summaries = metrics.map(summarizeMetric).filter(Boolean);
const outlierEvents = [];
for (const row of rows) {
    const timestamp = normalizeTimestamp(row.hour || row.timestamp || row.ts || null);
    for (const summary of summaries) {
        const value = parseMetric(row, summary.metric);
        if (value === null || Number(summary.mad_raw || 0) <= 0) continue;
        const z = Math.abs(0.6745 * (value - summary.median_raw) / summary.mad_raw);
        if (z >= threshold) {
            outlierEvents.push({
                metric: summary.metric,
                timestamp,
                value,
                robust_z: z,
                baseline_median: summary.median_raw,
                event_type: value >= summary.median_raw ? 'spike' : 'drop',
            });
        }
    }
}
outlierEvents.sort((a, b) => String(a.timestamp).localeCompare(String(b.timestamp)));

const outliersByMetric = {};
for (const event of outlierEvents) {
    outliersByMetric[event.metric] = (outliersByMetric[event.metric] || 0) + 1;
}

const costAnomalies = outlierEvents.filter((event) => String(event.metric).includes('cost') && event.event_type === 'spike');
const hints = [];
if (outlierEvents.length > 0) {
    hints.push('Detected statistically unusual points using robust z-score (MAD).');
} else {
    hints.push('No robust outliers detected for the selected metrics and window.');
}
if (costAnomalies.length > 0) {
    hints.push('Cost-related anomalies were detected and may reflect tariff or usage shifts.');
}

const context = {
    window: {
        start_ts: req.start_ts,
        end_ts: req.end_ts,
        timezone,
        rows_analyzed: rows.length,
    },
    baseline_stats: summaries.map((s) => ({
        count: s.count,
        mad: s.mad,
        max: s.max,
        mean: s.mean,
        median: s.median,
        metric: s.metric,
        min: s.min,
    })),
    outlier_events: outlierEvents,
    cost_anomalies: costAnomalies,
    narrative_hints: hints,
    summary: {
        total_outliers: outlierEvents.length,
        outliers_by_metric: outliersByMetric,
        selected_metrics: metrics,
    },
};

const fallbackOutput = {
    summary: `Fallback insight generated from deterministic analytics context: ${JSON.stringify(context.summary)}`,
    key_findings: hints.length > 0 ? hints.slice(0, 4) : ['No critical findings were detected for the requested interval.'],
    recommendations: [
        'Validate highlighted periods against operational logs and maintenance records.',
        'Trigger a dashboard refresh once upstream LLM connectivity is restored.'
    ],
};

const cacheEnabled = toBool(env.get('AI_INSIGHT_CACHE__ENABLED'), false);
const cachePrefix = env.get('AI_INSIGHT_CACHE__KEY_PREFIX') || 'ai-insight:cache:v1';
const cacheKey = [
    cachePrefix,
    'anomaly-report',
    access.agreement_id || 'unknown-agreement',
    access.asset_id || 'unknown-asset',
    req.start_ts || '',
    req.end_ts || '',
    timezone,
    String(threshold),
].join(':');
const cacheStore = global.get('aiInsightAnomalyCache') || {};
const reqHeaders = (msg.req && msg.req.headers) || {};
const rawCacheBypass = String(reqHeaders['x-insight-cache-bypass'] || reqHeaders['x-cache-bypass'] || '').trim().toLowerCase();
const cacheBypass = ['1', 'true', 'yes', 'on'].includes(rawCacheBypass);

const makeSuccessMsg = (result, llmUsed, llmModel, llmError) => {
    const outputId = makeOutputId();
    const timestamp = new Date().toISOString();
    const isDev = ['development', 'dev', 'local'].includes(String(env.get('AI_INSIGHT_SERVICE__ENVIRONMENT') || env.get('FACIS_ENV') || 'development').toLowerCase());
    msg.statusCode = 200;
    msg.headers = { 'Content-Type': 'application/json' };
    msg.payload = {
        insight_type: 'anomaly-report',
