let llmError = null;

if (Number(msg.statusCode || 0) >= 200 && Number(msg.statusCode || 0) < 300) {
    try {
        const payload = msg.payload || {};
        const model = payload.model || computed.llmModel || 'unknown-model';
        const content = payload && payload.choices && payload.choices[0] && payload.choices[0].message && payload.choices[0].message.content;
        let normalized = String(content).trim();
        normalized = normalized.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
        const parsed = JSON.parse(normalized);
        const payloadObj = parsed && (parsed.result || parsed.output || parsed);
        const summaryCandidate = payloadObj && (payloadObj.summary || payloadObj.overview || payloadObj.summary_text);
        const findingsCandidate = payloadObj && (payloadObj.key_findings || payloadObj.keyFindings || payloadObj.findings || payloadObj.keyPoints);
        const recommendationsCandidate = payloadObj && (payloadObj.recommendations || payloadObj.recommendation_list || payloadObj.actions || payloadObj.suggestions);

        const toStringArray = (value) => {
            if (Array.isArray(value)) return value.map((x) => String(x));
            if (typeof value === 'string') {
                return value
                    .split(/\n+/)
                    .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
                    .filter(Boolean);
            }
            if (value && typeof value === 'object') {
                if (Array.isArray(value.items)) return value.items.map((x) => String(x));
                if (Array.isArray(value.points)) return value.points.map((x) => String(x));
                if (Array.isArray(value.list)) return value.list.map((x) => String(x));
                if (typeof value.text === 'string') {
                    return value.text
                        .split(/\n+/)
                        .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
                        .filter(Boolean);
                }
            }
            return [];
        };

        const findings = toStringArray(findingsCandidate);
        const recommendations = toStringArray(recommendationsCandidate);
        if (!summaryCandidate || findings.length === 0 || recommendations.length === 0) {
            throw new Error('LLM output does not match expected schema: ' + JSON.stringify(parsed).slice(0, 240));
        }

        finalOutput = {
            summary: String(summaryCandidate),
            key_findings: findings,
            recommendations,
        };
        llmUsed = true;
        llmModel = String(model);
    } catch (error) {
        llmError = String(error && error.message ? error.message : error);
    }
} else {
