    if (value === undefined || value === null || value === '') return fallback;
    const lowered = String(value).trim().toLowerCase();
    if (['true', '1', 'yes', 'on'].includes(lowered)) return true;
    if (['false', '0', 'no', 'off'].includes(lowered)) return false;
    return fallback;
};

const parseList = (value, fallback) => {
    if (value === undefined || value === null || value === '') return fallback;
    try {
        const parsed = JSON.parse(value);
        if (Array.isArray(parsed)) return parsed.map((item) => String(item));
    } catch (_) {
        // ignore
    }
    return fallback;
};

const headers = (msg.req && msg.req.headers) || {};
const pickHeader = (name) => headers[String(name || '').toLowerCase()];

const policyEnabled = toBool(env.get('AI_INSIGHT_POLICY__ENABLED'), true);
const agreementHeader = env.get('AI_INSIGHT_POLICY__AGREEMENT_HEADER') || 'x-agreement-id';
const assetHeader = env.get('AI_INSIGHT_POLICY__ASSET_HEADER') || 'x-asset-id';
const roleHeader = env.get('AI_INSIGHT_POLICY__ROLE_HEADER') || 'x-user-roles';
const requiredRoles = parseList(env.get('AI_INSIGHT_POLICY__REQUIRED_ROLES'), ['ai_insight_consumer']);
const allowedAgreements = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_AGREEMENT_IDS'), []);
const allowedAssets = parseList(env.get('AI_INSIGHT_POLICY__ALLOWED_ASSET_IDS'), []);

const agreementId = String(pickHeader(agreementHeader) || '').trim();
const assetId = String(pickHeader(assetHeader) || '').trim();
const rawRoles = String(pickHeader(roleHeader) || '').trim();
const roles = rawRoles ? rawRoles.split(',').map((item) => item.trim()).filter(Boolean) : [];

if (policyEnabled) {
    if (!agreementId || !assetId || roles.length === 0) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Missing required governance headers' };
        return [null, msg, null];
    }

    const missingRole = requiredRoles.find((role) => !roles.includes(role));
    if (missingRole) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied: missing required role ' + missingRole };
        return [null, msg, null];
    }

    if (allowedAgreements.length > 0 && !allowedAgreements.includes(agreementId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for agreement_id' };
        return [null, msg, null];
    }

    if (allowedAssets.length > 0 && !allowedAssets.includes(assetId)) {
        msg.statusCode = 403;
        msg.headers = { 'Content-Type': 'application/json' };
        msg.payload = { detail: 'Policy denied for asset_id' };
        return [null, msg, null];
    }
}

const rateLimitEnabled = toBool(env.get('AI_INSIGHT_RATE_LIMIT__ENABLED'), true);
const rpm = Math.max(1, Number(env.get('AI_INSIGHT_RATE_LIMIT__REQUESTS_PER_MINUTE') || 10));
const limiterAgreement = agreementId || 'anonymous';

if (rateLimitEnabled) {
    const bucketKey = 'aiInsightRateLimitBuckets';
    const buckets = global.get(bucketKey) || {};
    const now = Date.now();
    const windowMs = 60 * 1000;
    let bucket = buckets[limiterAgreement];
    if (!bucket || now - bucket.windowStart >= windowMs) {
        bucket = { windowStart: now, count: 0 };
    }
    if (bucket.count >= rpm) {
        const retryAfter = Math.max(1, Math.ceil((bucket.windowStart + windowMs - now) / 1000));
        msg.statusCode = 429;
        msg.headers = {
            'Content-Type': 'application/json',
            'Retry-After': String(retryAfter),
        };
        msg.payload = { detail: 'Agreement rate limit exceeded' };
        buckets[limiterAgreement] = bucket;
        global.set(bucketKey, buckets);
        return [null, null, msg];
    }
    bucket.count += 1;
    buckets[limiterAgreement] = bucket;
    global.set(bucketKey, buckets);
}

msg.accessContext = {
    agreement_id: agreementId || 'unknown-agreement',
    asset_id: assetId || 'unknown-asset',
    roles,
};

return [msg, null, null];

const latest = global.get('aiInsightLatestOutputs') || {};
const outputsById = global.get('aiInsightOutputsById') || {};
if (msg && msg.payload && msg.payload.metadata) {
    const snapshot = JSON.parse(JSON.stringify(msg.payload));
    const metadata = snapshot.metadata || {};
    const outputId = String(metadata.output_id || '').trim();

    latest['anomaly-report'] = {
        cached_at: metadata.timestamp || new Date().toISOString(),
        output: snapshot,
    };
    global.set('aiInsightLatestOutputs', latest);

    const fallbackText = [
        String(snapshot.summary || ''),
        ...((Array.isArray(snapshot.key_findings) ? snapshot.key_findings : []).map((item) => '- ' + String(item))),
        ...((Array.isArray(snapshot.recommendations) ? snapshot.recommendations : []).map((item) => '- ' + String(item))),
    ].filter((line) => String(line).trim().length > 0).join('\n');

    if (outputId) {
        outputsById[outputId] = {
            id: outputId,
            insight_type: 'anomaly-report',
            agreement_id: String(metadata.agreement_id || 'unknown-agreement'),
            asset_id: String(metadata.asset_id || 'unknown-asset'),
            input_data: JSON.parse(JSON.stringify(msg.anomalyRequest || {})),
            llm_model: String(metadata.llm_model || 'rule-based-fallback'),
            output_text: (typeof msg._llmRawText === 'string' && msg._llmRawText.trim()) ? msg._llmRawText.trim() : fallbackText,
            structured_output: {
                summary: String(snapshot.summary || ''),
                key_findings: Array.isArray(snapshot.key_findings) ? snapshot.key_findings.map((item) => String(item)) : [],
                recommendations: Array.isArray(snapshot.recommendations) ? snapshot.recommendations.map((item) => String(item)) : [],
            },
            timestamp: String(metadata.timestamp || new Date().toISOString()),
        };
        global.set('aiInsightOutputsById', outputsById);
    }
}
return msg;

if (msg._anomalyResponseDispatched) {
    return null;
}
msg._anomalyResponseDispatched = true;

const detail = (msg.payload && msg.payload.detail)
    ? String(msg.payload.detail)
    : 'Upstream dependency failure while generating insight';

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail
};

return msg;

const sourceId = msg.error && msg.error.source && msg.error.source.id;
if (sourceId === 'http_resp_502_json') {
    return null;
}

if (!msg.res) {
    return null;
}

const alreadySent = !!(msg.res.headersSent || (msg.res._res && (msg.res._res.headersSent || msg.res._res.writableEnded)));
if (alreadySent) {
    return null;
}

msg.statusCode = 502;
msg.headers = {
    'Content-Type': 'application/json'
};
msg.payload = {
    detail: 'Upstream dependency failure while generating insight'
};
return msg;
